function strobogrammaticInRange(low, high) {
    let count = 0;
    for (let len = low.length; len <= high.length; ++len) {
        const num = helper(len, len);
        count += (num >= low && num <= high) ? 1 : 0;
    }
    return count;
}

function helper(m, n) {
    if (m === 0) return "";
    if (m === 1) return "0 1 8";
    if (n === 0) return "11 69 88 96";
    let res = "";
    for (const a of helper(m - 2, n).split(" ")) {
        if (m !== n) res += a + "0" + a + " ";
        res += a + "1" + a + " ";
        res += a + "6" + a + " ";
        res += a + "8" + a + " ";
        res += a + "9" + a + " ";
    }
    return res;
}
